exercises.solution:
def composed_degree(degrees: list) -> int:
    result = 1
    for d in degrees:
        result *= d
    return result

def isogeny_chain_length(target_degree: int, base_degree: int) -> int:
    import math
    return int(math.log(target_degree, base_degree))

import random
from collections import Counter

def random_walk(graph: dict, start: int, steps: int) -> int:
    current = start
    for _ in range(steps):
        neighbors = graph.get(current, [current])
        current = random.choice(neighbors)
    return current

def estimate_mixing(graph: dict, start: int, steps: int, trials: int) -> dict:
    endpoints = [random_walk(graph, start, steps) for _ in range(trials)]
    counts = Counter(endpoints)
    return {k: v / trials for k, v in counts.items()}
